const SHELL_CACHE="dunamis-shell-v4-1-1",SHELL_ASSETS=["./","./index.html","./main.css","./app.js","./config.js","./core/logger.js","./core/metrics.js","./core/error-tracker.js","./core/data-layer.js","./core/auth-service.js","./core/ui-bigbang.js","./services/supabase-service.js","./manifest.webmanifest"];self.addEventListener("install",e=>{e.waitUntil(caches.open(SHELL_CACHE).then(t=>t.addAll(SHELL_ASSETS))),self.skipWaiting()}),self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(t=>Promise.all(t.filter(c=>c!==SHELL_CACHE).map(c=>caches.delete(c))))),self.clients.claim()}),self.addEventListener("fetch",e=>{if(e.request.method!=="GET")return;const t=new URL(e.request.url);if(!(t.origin===self.location.origin))return;if(["/index.html","/app.js","/config.js","/main.css","/core/ui-bigbang.js"].some(s=>t.pathname.endsWith(s))){e.respondWith(fetch(e.request).then(s=>{const i=s.clone();return caches.open(SHELL_CACHE).then(r=>r.put(e.request,i)),s}).catch(()=>caches.match(e.request).then(s=>s||caches.match("./index.html"))));return}e.respondWith(caches.match(e.request).then(s=>s||fetch(e.request).then(i=>{const r=i.clone();return caches.open(SHELL_CACHE).then(n=>n.put(e.request,r)),i}).catch(()=>caches.match("./index.html"))))});
